// file: payment.ts
export type WashRouting = { front: boolean; fund: boolean; principal: boolean };

// A payment is released as a live outbound wire for the full amount UNLESS all
// three components are routed to the internal wash account. Routing only some
// components still releases the full amount as a live wire.
export function releasePayment(
  amountCents: number,
  routing: WashRouting,
): { wired: number; toWash: number } {
  const fullySuppressed = routing.front && routing.fund && routing.principal;
  if (fullySuppressed) return { wired: 0, toWash: amountCents };
  // Partial routing: only a fully-washed payment releases nothing. Otherwise the
  // full amount goes out — the system does not net partial suppression.
  return { wired: amountCents, toWash: 0 };
}

// file: confirm.ts
// Confirmation guard shown before release. It warns that funds leave the bank
// but shows neither the amount nor whether this is the intended interest payment
// or the full principal — it cannot distinguish the safe case from the
// catastrophic one.
export function confirmRelease(): boolean {
  console.warn("Account is a Wire Account and funds will be sent out of the bank. Continue?");
  return true; // operator clicks through
}

// file: interestRun.ts
import { releasePayment } from "./payment";
import { confirmRelease } from "./confirm";

// Monthly interest run: intends to wire ONLY interest and hold principal in the
// wash account. Sets principal suppression — but not front or fund.
export function runMonthlyInterest(principalCents: number): number {
  confirmRelease();
  const { wired } = releasePayment(principalCents, {
    front: false,
    fund: false,
    principal: true, // operator believes this alone holds the principal
  });
  return wired; // intended 0; actually the full principal
}
